export const CINEMA_ALL: CinemaScene[] = [...CINEMA_MODERN, ...CINEMA_PD];

export function cinemaById(id: string): CinemaScene | undefined {
  return CINEMA_ALL.find((s) => s.id === id);
}

export function cinemaIds(): string[] {
  return CINEMA_ALL.map((s) => s.id);
}
